module RefModule(input [3:0] A, input [3:0] B, input C, output [3:0] S);wire [3:0] sum;
    wire [3:0] diff;

    //summing A and B
      wire _n01 = A[0] ^ B[0];
  wire _c01 = A[0] & B[0];
  wire _n02 = A[1] ^ B[1] ^ _c01;
  wire _c02 = (A[1] & B[1]) | (A[1] & _c01) | (B[1] & _c01);
  wire _n03 = A[2] ^ B[2] ^ _c02;
  wire _c03 = (A[2] & B[2]) | (A[2] & _c02) | (B[2] & _c02);
  wire _n04 = A[3] ^ B[3] ^ _c03;
  wire _c04 = (A[3] & B[3]) | (A[3] & _c03) | (B[3] & _c03);
  assign sum = {_n01, _n02, _n03, _n04};

    //finding the difference between A and B
    assign diff = A - B;

    //outputting the sum or difference based on control input C
    assign S = C ? diff : sum;

endmodule
